{
  "type": "DRAG_FILL",
  "lessonText": "Let's start with a fun challenge to learn some basic Burmese vocabulary.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks with the correct Burmese words.",
        "codeTemplate": "I love ___ and ___.",
        "options": ["စာအုပ်", "စား", "ရေ", "မုန့်"],
        "correctAnswer": "စာအုပ်,မုန့်",
        "explanation": "The correct words are 'book' and 'cake' in Burmese."
      },
      {
        "instruction": "Complete the sentence with the right words.",
        "codeTemplate": "My favorite color is ___.",
        "options": ["အပြာ", "အနက်", "အဖြူ", "အိမ်"],
        "correctAnswer": "အပြာ",
        "explanation": "The correct word is 'blue' in Burmese."
      },
      {
        "instruction": "Choose the right words to fill in the blanks.",
        "codeTemplate": "I want to eat ___.",
        "options": ["သစ်သီး", "အစားအစာ", "ရေ", "မုန့်"],
        "correctAnswer": "အစားအစာ",
        "explanation": "The correct word is 'food' in Burmese."
      },
      {
        "instruction": "Fill in the blanks with appropriate Burmese vocabulary.",
        "codeTemplate": "I am going to the ___.",
        "options": ["ဧည့်ခန်း", "ရုံး", "စျေး", "ကျောင်း"],
        "correctAnswer": "ကျောင်း",
        "explanation": "The correct word is 'school' in Burmese."
      }
    ]
  }
}
